#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll,ll>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5,MOD=1e8-3;
PII a[MAXN], b[MAXN];
ll n, c[MAXN], p[MAXN],ans=0;
ll lowbit(ll x)
{
	return x & -x;
}
void fix(ll x, ll y)
{
	for (ll i = x; i <= n; i += lowbit(i))
	{
		c[i] += y;
	}
}
ll sum(ll x)
{
	ll ans = 0;
	for (ll i = x; i; i -= lowbit(i))
	{
		ans += c[i];
	}
	return ans;
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n=read();
	for(int i=1;i<=n;++i)
	{
		a[i].first=read();
		a[i].second=i;
	}
	for(int i=1;i<=n;++i)
	{
		b[i].first=read();
		b[i].second=i;
	}
	sort(a+1,a+n+1);
	sort(b+1,b+n+1);
	for(int i=1;i<=n;++i)
	{
		p[a[i].second]=b[i].second;
	}
	for(int i=1;i<=n;++i)
	{
		fix(p[i],1);
		ans=(ans+i-sum(p[i]))%MOD;
	}
	write(ans);
	return false;
}
